import * as fs from 'fs';
import * as path from 'path';

// This script "steals" the phoneme data from the Klatt-style synthesizer
// and converts it into a format digestible by the Acoustic Vacuum Siphon.

// Resolve paths relative to this script's location
const projectRoot = path.resolve(__dirname, '../../..');
const synthesizerPath = path.join(projectRoot, 'apps/edge-workers/src/lib/wasm-tts-engine.ts');
const outputPath = path.join(projectRoot, 'open-source/aether/src/phoneme-geometries.json');

const content = fs.readFileSync(synthesizerPath, 'utf8');

// Use regex to extract the PHONEMES constant
const phonemeMatch = content.match(/const PHONEMES: Record<string, PhonemeSpec> = ({[\s\S]+?});/);

if (!phonemeMatch) {
  console.error('Failed to find PHONEMES constant in wasm-tts-engine.ts');
  process.exit(1);
}

// Minimal parser for the TypeScript object literal
const rawPhonemes = phonemeMatch[1];
const phonemeLines = rawPhonemes.split('\n');

const geometries: any[] = [];
let currentPhoneme: any = null;

for (const line of phonemeLines) {
  const nameMatch = line.match(/^\s*([A-Z]+):\s*{/);
  if (nameMatch) {
    currentPhoneme = { id: nameMatch[1] };
    continue;
  }

  if (currentPhoneme) {
    const propertyMatch = line.match(/^\s*([a-z0-9]+):\s*([^,]+),/);
    if (propertyMatch) {
      const key = propertyMatch[1];
      const val = propertyMatch[2].trim();
      currentPhoneme[key] = val === 'true' ? true : val === 'false' ? false : parseFloat(val);
    }

    if (line.match(/^\s*},/)) {
      geometries.push(currentPhoneme);
      currentPhoneme = null;
    }
  }
}

fs.writeFileSync(outputPath, JSON.stringify(geometries, null, 2));

console.log(`Successfully extracted ${geometries.length} phoneme geometries to ${outputPath}`);